const authority = $json.authority_score;
const relevance = $json.relevance_score;
const spam = $json.spam_score;

const final_score =
Math.round(
(authority * 0.3) +
(relevance * 0.5) -
(spam * 0.2)
);

let priority = "LOW";
let suggested_action = "Ignore";

if(final_score >= 80){
  priority = "HIGH";
  suggested_action = "Immediate Outreach";
}
else if(final_score >= 50){
  priority = "MEDIUM";
  suggested_action = "Monitor & Outreach";
}

return {
  analysis_id: $json.analysis_id,

  source_domain: $json.source_domain,
  domain_rating: $json.domain_rating,

  authority_score: authority,
  relevance_score: relevance,
  spam_score: spam,

  domain_rating_score: authority,
  difficulty_score: spam,

  final_score,
  priority,
  suggested_action,

  recommendation: $json.recommendation,
  relevance_reason: $json.relevance_reason
};

return [{
    json: {
        success: false,
        agent: "Agent 3",
